-- Auto Seed wiring diagnostic (Track C Step 3.2 / 3.4 / New Layout Protocol)
-- Run on WIN-SQL002 Parsely DB. Replace @DocId / @ProcessId as needed.

DECLARE @ProcessId uniqueidentifier = '27900FAD-7BFD-48FF-85E7-C6F18C149521'; -- Invoice
DECLARE @DocId uniqueidentifier = '00000000-0000-0000-0000-000000000000'; -- replace for per-doc checks

PRINT '=== Invoice process — linear pipeline chain ===';
DECLARE @Json nvarchar(max) = (SELECT PipelineJson FROM parsely.Processes WHERE Id = @ProcessId);
DECLARE @Entry nvarchar(200) = JSON_VALUE(@Json, '$.entryStepId');
DECLARE @Steps nvarchar(max) = JSON_QUERY(@Json, '$.steps');
DECLARE @Cur nvarchar(200) = @Entry, @Ord int = 0;
WHILE @Cur IS NOT NULL AND @Ord < 25
BEGIN
    SET @Ord = @Ord + 1;
    SELECT
        @Ord AS Ord,
        @Cur AS StepId,
        JSON_VALUE(@Steps, CONCAT('$."', @Cur, '".type')) AS StepType,
        JSON_VALUE(@Steps, CONCAT('$."', @Cur, '".configJson')) AS ConfigJson,
        JSON_VALUE(JSON_QUERY(@Steps, CONCAT('$."', @Cur, '".next')), '$[0]') AS NextStepId;
    DECLARE @Next nvarchar(max) = JSON_QUERY(@Steps, CONCAT('$."', @Cur, '".next'));
    SET @Cur = CASE WHEN @Next IS NULL OR @Next = '[]' THEN NULL ELSE JSON_VALUE(@Next, '$[0]') END;
END;

PRINT '=== Global Auto Seed indicators ===';
SELECT
    (SELECT COUNT(*) FROM parsely.FieldLocators WHERE IsActive = 1 AND Name LIKE 'AI-seeded%') AS Ai[...truncated, total 3309 chars]
FROM parsely.FieldLocators fl
JOIN parsely.ExtractionFieldDefinitions f ON f.Id = fl.FieldDefinitionId
WHERE f.DocumentClassId = @ClassId
  AND (fl.Name LIKE 'AI-seeded%' OR fl.LocatorType IN (0, 4))
ORDER BY f.FieldName, fl.Priority;

PRINT '=== Audit — verify-time seed (Path B) ===';
SELECT ae.Timestamp, ae.Action, ae.Details
FROM parsely.AuditEntries ae
WHERE ae.DocumentId = @DocId
  AND (ae.Details LIKE 'AutoSeedFromVerify%' OR ae.Details LIKE 'Verified%')
ORDER BY ae.Timestamp DESC;

